import { RuleTester } from 'eslint';
import tseslint from 'typescript-eslint';
import { noDomAccess } from "../../rules/no-dom-access.js";
import { languageOptions } from "../../runtime.js";
const ruleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parserOptions: {
            ecmaVersion: 'latest',
            sourceType: 'module',
            ecmaFeatures: {
                jsx: true,
            },
        },
    },
});
// Separate tester for TypeScript code
const tsRuleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parser: tseslint.parser,
        parserOptions: {
            ecmaVersion: 'latest',
            sourceType: 'module',
        },
    },
});
describe('no-dom-access', () => {
    // Main test suite with JavaScript code
    ruleTester.run('no-dom-access', noDomAccess, {
        valid: [
            {
                name: 'allows document as a local variable',
                code: `
          const document = { body: null };
          document.querySelector('.test');
        `,
            },
            {
                name: 'allows document as a function parameter',
                code: `
          function parse(document) {
            return document.body;
          }
        `,
            },
            {
                name: 'allows document as a destructured property',
                code: `
          const { document } = customParser;
          document.parse();
        `,
            },
            {
                name: 'allows document property on other objects',
                code: `
          const parser = { document: {} };
          parser.document.parse();
        `,
            },
            {
                name: 'allows string "document" in code',
                code: `
          const selector = 'document.body';
          // Check document for changes
        `,
            },
            {
                name: 'allows UI Extensions components',
                code: `
          import { Text, Button } from '@hubspot/ui-extensions';
          function Component() {
            return <Text>Hello</Text>;
          }
        `,
            },
        ],
        invalid: [
            {
                name: 'reports error for direct document identifier usage',
                code: `
          const element = document.querySelector('.test');
        `,
                errors: [
                    {
                        messageId: 'noDomAccess',
                    },
                ],
            },
            {
                name: 'reports error for document method calls',
                code: `
          document.getElementById('test');
          document.querySelector('.class');
          document.querySelectorAll('div');
          document.createElement('div');
        `,
                errors: [
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                ],
            },
            {
                name: 'reports error for document property access',
                code: `
          const body = document.body;
          const head = document.head;
          const cookie = document.cookie;
        `,
                errors: [
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                ],
            },
            {
                name: 'reports error for document reference assignment',
                code: `
          const doc = document;
          doc.querySelector('.test');
        `,
                errors: [
                    {
                        messageId: 'noDomAccess',
                    },
                ],
            },
            {
                name: 'reports error for window.document access',
                code: `
          window.document.querySelector('.test');
          window.document.body;
          window['document'].getElementById('test');
        `,
                errors: [
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                ],
            },
            {
                name: 'reports error for globalThis.document access',
                code: `
          globalThis.document.querySelector('.test');
          globalThis['document'].body;
        `,
                errors: [{ messageId: 'noDomAccess' }, { messageId: 'noDomAccess' }],
            },
            {
                name: 'reports error for self.document access',
                code: `
          self.document.querySelector('.test');
          self['document'].getElementById('test');
        `,
                errors: [{ messageId: 'noDomAccess' }, { messageId: 'noDomAccess' }],
            },
            {
                name: 'reports error in React component with JSX',
                code: `
          import { Text } from '@hubspot/ui-extensions';
          function Component() {
            const element = document.querySelector('.test');
            return <Text>Hello</Text>;
          }
        `,
                errors: [{ messageId: 'noDomAccess' }],
            },
            {
                name: 'reports error in async, arrow, and class method contexts',
                code: `
          async function test1() { document.querySelector('.test'); }
          const test2 = () => document.body;
          class Test { method() { return document.head; } }
        `,
                errors: [
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                    { messageId: 'noDomAccess' },
                ],
            },
            {
                name: 'reports error in try/catch and nested scopes',
                code: `
          try {
            document.querySelector('.test');
          } catch (e) {
            console.log(e);
          }
          function outer() {
            function inner() {
              return document.body;
            }
          }
        `,
                errors: [{ messageId: 'noDomAccess' }, { messageId: 'noDomAccess' }],
            },
            {
                name: 'reports error for chained property access',
                code: `
          const title = document.body.firstChild;
        `,
                errors: [
                    {
                        messageId: 'noDomAccess',
                    },
                ],
            },
            {
                name: 'reports error for document in conditional',
                code: `
          if (document.body) {
            console.log('body exists');
          }
        `,
                errors: [
                    {
                        messageId: 'noDomAccess',
                    },
                ],
            },
        ],
    });
    // TypeScript-specific tests (requires TypeScript parser)
    tsRuleTester.run('no-dom-access (TypeScript)', noDomAccess, {
        valid: [
            {
                name: 'allows document type in type alias',
                code: `
          type DocumentType = typeof document;
        `,
            },
            {
                name: 'allows document type in interface property',
                code: `
          interface Parser {
            doc: typeof document;
          }
        `,
            },
            {
                name: 'allows document type in function return type',
                code: `
          function getDoc(): typeof document {
            return {} as any;
          }
        `,
            },
            {
                name: 'allows Document type references',
                code: `
          interface CustomElement extends Document {
            customMethod(): void;
          }
        `,
            },
        ],
        invalid: [
            {
                name: 'reports error for document usage even after type declarations',
                code: `
          type DocumentType = typeof document;

          function getData() {
            const element = document.querySelector('.test');
          }
        `,
                errors: [
                    {
                        messageId: 'noDomAccess',
                    },
                ],
            },
            {
                name: 'reports error for document in TypeScript with explicit types',
                code: `
          const element: HTMLElement | null = document.querySelector('.test');
        `,
                errors: [
                    {
                        messageId: 'noDomAccess',
                    },
                ],
            },
        ],
    });
});
